// ScaledConfig derives SWIM parameters from the estimated cluster size.
//
// The protocol period is represented by SWIMConfig.ProbeInterval. Each
// logarithmic size bucket adds the configured step values to Base, so larger
// clusters probe less frequently while small clusters keep the base timings.
type ScaledConfig struct {
	// Base is used for cluster sizes 0 and 1 before logarithmic growth applies.
	Base SWIMConfig
	// ProtocolPeriodStep is added to ProbeInterval for each log2 size bucket.
	ProtocolPeriodStep time.Duration
	// ProbeTimeoutStep is added to ProbeTimeout for each log2 size bucket.
	ProbeTimeoutStep time.Duration
	// SuspicionTimeoutStep is added to SuspicionTimeout for each log2 size bucket.
	SuspicionTimeoutStep time.Duration
	// IndirectCheckStep is added to IndirectChecks for each log2 size bucket.
	IndirectCheckStep int
	// MaxIndirectChecks caps scaled indirect fanout. A value of 0 means no cap.
	MaxIndirectChecks int
}

// DefaultScaling returns log2-based defaults for deriving SWIM parameters.
func DefaultScaling() ScaledConfig {
	return ScaledConfig{
		Base:                  DefaultSWIMConfig(),
		ProtocolPeriodStep:    250 * time.Millisecond,
		ProbeTimeoutStep:      50 * time.Millisecond,
		SuspicionTimeoutStep:  time.Second,
		IndirectCheckStep:     1,
		MaxIndirectChecks:     16,
	}
}

// ConfigForClusterSize returns SWIM parameters scaled for clusterSize.
func (c ScaledConfig) ConfigForClusterSize(clusterSize int) SWIMConfig {
	bucket := log2Bucket(clusterSize)
	return SWIMConfig{
		ProbeInterval:    c.ProtocolPeriod(clusterSize),
		ProbeTimeout:     scaledDuration(c.Base.ProbeTimeout, c.ProbeTimeoutStep, bucket),
		IndirectChecks:   c.IndirectChecks(clusterSize),
		SuspicionTimeout: scaledDuration(c.Base.SuspicionTimeout, c.SuspicionTimeoutStep, bucket),
	}
}

// ProtocolPeriod returns the scaled SWIM protocol period for clusterSize.
func (c ScaledConfig) ProtocolPeriod(clusterSize int) time.Duration {
	return scaledDuration(c.Base.ProbeInterval, c.ProtocolPeriodStep, log2Bucket(clusterSize))
}

// IndirectChecks returns the scaled indirect probe fanout for clusterSize.
func (c ScaledConfig) IndirectChecks(clusterSize int) int {
	step := c.IndirectCheckStep
	if step < 0 {
		step = 0
	}
	checks := c.Base.IndirectChecks
	if checks < 0 {
		checks = 0
	}
	checks += step * log2Bucket(clusterSize)
	if c.MaxIndirectChecks > 0 && checks > c.MaxIndirectChecks {
		return c.MaxIndirectChecks
	}
	return checks
}

func scaledDuration(base, step time.Duration, bucket int) time.Duration {
	if base < 0 {
		base = 0
	}
	if step < 0 {
		step = 0
	}
	return base + time.Duration(bucket)*step
}

func log2Bucket(clusterSize int) int {
	if clusterSize <= 1 {
		return 0
	}
	return bits.Len(uint(clusterSize)) - 1
}

// ClusterSizeEstimator tracks unique observed node IDs and reports a current
// cluster size estimate for scaled configuration.
type ClusterSizeEstimator struct {
	mu    sync.RWMutex
	nodes map[string]struct{}
}

// NewClusterSizeEstimator returns an empty cluster size estimator.
func NewClusterSizeEstimator() *ClusterSizeEstimator {
	return &ClusterSizeEstimator{
		nodes: make(map[string]struct{}),
	}
}

// Observe records a node ID. Repeated observations of the same ID are counted once.
func (e *ClusterSizeEstimator) Observe(id string) int {
	e.mu.Lock()
	defer e.mu.Unlock()
	if e.nodes == nil {
		e.nodes = make(map[string]struct{})
	}
	e.nodes[id] = struct{}{}
	return len(e.nodes)
}

// ObserveMembers records a batch of node IDs. Repeated IDs are counted once.
func (e *ClusterSizeEstimator) ObserveMembers(ids ...string) int {
	e.mu.Lock()
	defer e.mu.Unlock()
	if e.nodes == nil {
		e.nodes = make(map[string]struct{})
	}
	for _, id := range ids {
		e.nodes[id] = struct{}{}
	}
	return len(e.nodes)
}

// Estimate returns the number of unique node IDs observed.
func (e *ClusterSizeEstimator) Estimate() int {
	e.mu.RLock()
	defer e.mu.RUnlock()
	return len(e.nodes)
}

// Reset clears all observed node IDs.
func (e *ClusterSizeEstimator) Reset() {
	e.mu.Lock()
	defer e.mu.Unlock()
	e.nodes = make(map[string]struct{})
}

